module GPIO_Controller (
    input wire clk,
    input wire rst,
    input wire we,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] pin_values;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            pin_values <= 8'b00000000;
        end else if (we) begin
            pin_values <= data_in;
        end
    end

    always @(*) begin
        data_out = pin_values;
    end
endmodule
